def decode_hieroglyphic_sum(hieroglyphs: str) -> int:
    roman_values = {'I': 1, 'V': 5, 'X': 10}
    total = 0
    for i in range(len(hieroglyphs)):
        if hieroglyphs[i] == 'I':
            total += roman_values[hieroglyphs[i]]
        elif hieroglyphs[i] == 'V':
            total += roman_values[hieroglyphs[i]]
        elif hieroglyphs[i] == 'X':
            if i > 0 and hieroglyphs[i - 1] != 'I' and hieroglyphs[i - 1] != 'V':
                total -= 2 * roman_values[hieroglyphs[i - 1]]
            total += roman_values[hieroglyphs[i]]
    return total
